"""
MKT Original Layer — Jeremiah chapters 4–6
Run: python3 scripts/zc-original-jeremiah-4-6-fill.py

Key lexical decisions:
- shuv (4:1): the governing verb of Jeremiah's entire call; the conditional structure
  of 4:1-2 is two independent 'if you return' clauses, making return the only
  precondition for avoiding exile.
- tohu va-vohu (4:23): un-creation language from Gen 1:2; Jeremiah's vision of
  judgment as the reversal of creation is one of the most theologically loaded
  images in the OT.
- heart circumcision (4:4): the inner-Torah demand that Jeremiah makes explicit;
  Paul's Rom 2:28-29 cites the same concept.
- shalom shalom (6:14): the false-prophet formula; the double noun is a grammatical
  intensifier ('complete peace, total peace') that makes the lie more emphatic.
- derekh haolam / derakhim haolam (6:16): 'ancient paths' — literally the ways of
  the age or the ways of the world; nuach (rest) here echoes Matt 11:28-29.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

JER_ORIGINAL = {
  "4": {
    "1": "<p><strong>im-tashuv Yisrael ... im tashuv elai</strong> (<em>ʾim-tāšûb yiśrāʾēl ... ʾim tāšûb ʾēlay</em>): 'If you return, O Israel ... if you return to me.' <em>Shuv</em> (return/repent) is the single most important word in Jeremiah&apos;s vocabulary, occurring over 100 times in the book. The double conditional here — return generally, and then specifically &apos;to me&apos; — captures Jeremiah&apos;s insistence that repentance is not ritual or geographic but relational and directional: it is a turning <em>toward</em> YHWH himself. The negative formulation &apos;you will not be driven away&apos; (<em>lo-tanud</em>) makes exile the default outcome if the return does not happen.</p>",
    "2": "<p><strong>nishbata chai YHWH be-emet be-mishpat uve-tzedaqah</strong> (<em>nišbāʿtā ḥay Yhwh beʾĕmet bĕmišpāṭ ûbĕṣĕdāqāh</em>): &apos;You shall swear, &apos;As the LORD lives,&apos; in truth, in justice, and in righteousness.&apos; The three attributes — <em>emet</em> (truth/faithfulness), <em>mishpat</em> (justice), <em>tzedaqah</em> (righteousness) — are the three pillars of covenant loyalty and the same triad Hosea uses for the renewed covenant in Hos 2:19-20. An oath &apos;as the LORD lives&apos; is the highest covenant speech act; for it to be valid, the swearer must embody the same qualities that characterize YHWH himself. The nations blessing themselves by YHWH (v. 2b) anticipates the Abrahamic blessing (Gen 12:3), available only when Israel lives as a covenant people.</p>",
    "3": "<p><strong>niru lachem nir veal-tizru el-qotzim</strong> (<em>nîrû lākem nîr wĕʾal-tizrĕʿû ʾel-qôṣîm</em>): &apos;Break up your fallow ground and do not sow among thorns.&apos; The agricultural metaphor for spiritual preparation: <em>niru</em> (break up / plow fallow ground) uses the same root as <em>nir</em> (untilled ground). Sowing seed without preparing the soil — specifically without removing thorns — wastes the seed and guarantees a choked harvest. Jesus&apos;s parable of the sower (Mark 4:7, 18-19) applies this same image: seed sown among thorns is choked by cares and riches. Jeremiah&apos;s agricultural metaphor anticipates the parable&apos;s diagnostic of unrepared hearts.</p>",
    "4": "<p><strong>himolu l-YHWH vasiru arlos levavchem</strong> (<em>himmōlû lYhwh wĕsîrû ʿorlôt lĕbabkem</em>): &apos;Circumcise yourselves to the LORD and remove the foreskins of your hearts.&apos; <em>Orlah</em> (foreskin/uncircumcision) applied to the heart appears also in Lev 26:41 and Deut 10:16 and 30:6. The physical sign of the Abrahamic covenant (Gen 17) becomes the demand for an inner transformation: the outer cut must correspond to an inner removal of the obstruction to covenant faithfulness. Paul&apos;s argument in Rom 2:28-29 — &apos;true circumcision is of the heart, by the Spirit, not the letter&apos; — is the NT formulation of exactly what Jeremiah here demands; Paul is not inventing a new concept but drawing out the Jeremianic logic that inner circumcision is what the outer sign was always pointing toward.</p>",
    "5": "<p><strong>tiq&apos;u shofar ba-aretz</strong> (<em>tiqʿû šôpār bāʾāreṣ</em>): &apos;Sound the trumpet throughout the land.&apos; The <em>shofar</em> (ram&apos;s horn trumpet) served as both a military alarm and a covenant-assembly signal (cf. Num 10). Its sounding inaugurated fasts, new moons, and the Day of Atonement (Lev 25:9). Here its covenant-assembly function is perverted into a war-alarm: the sacred instrument that called Israel to worship now calls them to flee. Gathering (&apos;assemble together&apos;) is the gathering not for worship but for survival.</p>",
    "6": "<p><strong>sera&apos; nesi el-tzion</strong> (<em>śĕʾû-nes ʾel-ṣiyyôn</em>): &apos;Raise the signal flag toward Zion.&apos; The signal (<em>nes</em>) or standard was a rallying point visible from a distance — associated with Isaiah&apos;s eschatological visions of nations streaming to Zion (Isa 11:12; 49:22). Here the same signal is used in reverse: not a beacon drawing the nations to peace but a marker pointing to the city under siege. The disaster from the north (<em>tsafon</em>) is Jeremiah&apos;s standard designation for Babylon, though at the time of composition (ca. 627-605 BCE) the identity of the northern power was not yet fully determined.</p>",
    "7": "<p><strong>alah aryeh misuvko</strong> (<em>ʿālāh ʾaryēh miśśubkô</em>): &apos;The lion has come out of his thicket.&apos; The lion is one of Jeremiah&apos;s most repeated images for Babylon (4:7; 5:6; 25:38; 49:19; 50:17, 44). <em>Mashchit goyim</em> (destroyer of nations): a title that appears again at 6:26 and 51:25, where YHWH himself uses it of Babylon. The theological move is significant: Babylon, the destroyer of nations, is YHWH&apos;s instrument — a truth that makes Jeremiah deeply unpopular (cf. 27:6: &apos;I have given all these lands to Nebuchadnezzar my servant&apos;).</p>",
    "8": "<p><strong>chagru sakim sepedu u-veilu</strong> (<em>ḥigĕrû śaqqîm sipĕdû ûbĕkû</em>): &apos;Put on sackcloth, wail and howl.&apos; The lamentation ritual vocabulary: <em>saq</em> (sackcloth, coarse goat-hair fabric worn as a sign of mourning or penitence), <em>saphad</em> (wail/lament in a formal mourning sense), <em>yalal</em> (howl, the animal-like cry of extreme grief). The three verbs together evoke the communal mourning rite, but Jeremiah uses them proleptically — before the disaster, not after — demanding mourning as appropriate response to the already-determined judgment.</p>",
    "9": "<p><strong>lev-hamelech yoved vylev hasarim</strong> (<em>lēb-hammelek yōbēd wĕlēb haśśārîm</em>): &apos;The king&apos;s heart will fail and the courage of the officials.&apos; <em>Lev</em> (heart) in Hebrew is the center of will, courage, and decision-making — not primarily emotion as in English. The &apos;heart failing&apos; idiom means loss of will and determination (cf. Deut 20:8; Josh 2:11: &apos;our hearts melted&apos;). The priests are &apos;horrified&apos; (<em>shamem</em>, the same root as the &apos;abomination of desolation&apos;) and the prophets &apos;stunned&apos; (<em>tamah</em>). The three leadership groups — king, priests, prophets — all fail simultaneously.</p>",
    "10": "<p><strong>hissata et-ha&apos;am hazeh veeth Yerushalaim lemor shalom yihyeh lachem</strong> (<em>hiššêtā ʾet-hāʿam hazzeh wĕʾet-yĕrûšālaim lēmōr šālôm yihyeh lākem</em>): &apos;You have truly deceived this people and Jerusalem, saying, &apos;You shall have peace.&apos;&apos; This is one of the most theologically shocking verses in the prophets: Jeremiah appears to accuse YHWH himself of deception. The verb <em>nasha</em> (deceive/beguile) is used of Eve&apos;s deception in Gen 3:13. Various interpretations: (1) Jeremiah is quoting what false prophets have claimed YHWH said; (2) Jeremiah is expressing his own anguished confusion (cf. 20:7: &apos;O LORD, you deceived me&apos;); (3) Jeremiah reflects the genuine ambiguity of how to read YHWH&apos;s past covenant promises of peace when disaster comes. In context, the verse more likely continues the lament: YHWH allowed false prophets to give false assurances.</p>",
    "11": "<p><strong>ruach tsah shefahim bamidbar</strong> (<em>rûaḥ ṣāḥ šĕpāʿîm bammidbar</em>): &apos;A scorching wind from the bare heights of the wilderness.&apos; The <em>shefahim</em> (bare heights/desolate heights) are the exposed hilltops of the Judean desert — uninhabited and wind-swept. The east wind (<em>qadim</em>, from 4:11-12&apos;s implied direction) is the fierce desert wind (<em>sirocco</em>) that withers vegetation and brings oppressive heat. The key distinction: this is &apos;not to winnow grain or to cleanse&apos; — ordinary agricultural winds serve those purposes, but this wind is for judgment only, overwhelming and purposeless from an economic standpoint.</p>",
    "12": "<p><strong>atah gam ani adaber mishpatim otam</strong> (<em>ʾattāh gam-ʾănî ʾădabbēr mišpāṭîm ʾôtām</em>): &apos;Now I will pronounce judgment against them.&apos; The switch to first-person divine speech mid-oracle. <em>Mishpatim</em> (judgments/legal decisions) carries the force of a court verdict: YHWH is both the aggrieved party and the judge, delivering a forensic sentence. The phrase &apos;at my command&apos; (<em>mimeni</em>, &apos;from me&apos;) establishes that even the devastating wind of v. 11 is under divine authority.</p>",
    "13": "<p><strong>hinei kashananiyim ya&apos;aleh</strong> (<em>hinnēh kaʿănānîm yaʿăleh</em>): &apos;Look — he advances like storm clouds.&apos; The comparison to storm clouds, chariots like whirlwinds (<em>sûphah</em>), and horses swifter than eagles (<em>nesharim</em>) builds an overwhelming image of unstoppable speed. The eagle (<em>nesher</em>) was the fastest creature in ancient Near Eastern imagination (cf. Deut 28:49; Hab 1:8). The exclamation &apos;we are doomed&apos; (<em>oy lanu</em>, &apos;woe to us&apos;) is in the mouth of the people who see the invasion coming and can do nothing.</p>",
    "14": "<p><strong>kabsi mirah libech Yerushalaim l&apos;ma&apos;an tivashah&apos;i</strong> (<em>kabbĕsî mērāʿāh libbēk yĕrûšālaim lĕmaʿan tiwwāšĕʿî</em>): &apos;Wash the evil from your heart, O Jerusalem, so that you may be saved.&apos; The verb <em>kabas</em> (wash/launder) is used for ritual cleansing of clothes and of persons (Lev 13-14; Ps 51:2: &apos;wash me thoroughly from my iniquity&apos;). The linkage of &apos;evil from your heart&apos; with &apos;so that you may be saved&apos; makes salvation conditional on inner moral washing — not on external ritual compliance. The <em>machshevot aven</em> (wicked schemes, literally &apos;plans of wickedness&apos;) that need to be expelled are the deliberate strategies of unfaithfulness, not accidental lapses.</p>",
    "15": "<p><strong>qol magid midan uma&apos;avim mashmi&apos;a aven</strong> (<em>qôl maggîd middān ûmaśmîaʿ ʾāwen mehar ʾeprayim</em>): &apos;A voice proclaims from Dan and announces disaster from Mount Ephraim.&apos; Dan, the northernmost city of Israel, and Mount Ephraim (the central highlands) mark the geographic progression of bad news traveling south toward Jerusalem. The voice announcing disaster moves through the tribal territory like a wave — each reporting post relays the news of the incoming invasion. This geographical sequence would be familiar to Judean hearers who knew the traditional tribal territory names.</p>",
    "16": "<p><strong>hazkiru lagoyim hinei hashmi&apos;u al-Yerushalaim</strong> (<em>hazzekîrû laggôyim hinnēh haššmîʿû ʿal-yĕrûšālaim</em>): &apos;Tell the nations; announce concerning Jerusalem: Besiegers are coming from a distant land.&apos; The command to &apos;tell the nations&apos; inverts the expected missionary direction: instead of the nations learning of YHWH&apos;s greatness from Israel, the nations are called as witnesses to Israel&apos;s humiliation. The <em>notzrim</em> (besiegers/watchers) coming from a distant land echoes Deut 28:49-50&apos;s covenant curse: &apos;the LORD will bring against you a nation from far away, from the end of the earth&apos; — Jeremiah is announcing the arrival of exactly what Moses warned would happen if the covenant were broken.</p>",
    "17": "<p><strong>ki-marat bi neum YHWH</strong> (<em>kî mārāt bî nĕʾum Yhwh</em>): &apos;Because she has rebelled against me, declares the LORD.&apos; The single word <em>marah</em> (rebel/be bitter/be obstinate) explains the entire invasion. The root conveys active, willful defiance — not mere failure but deliberate turning against. The same word appears in the wilderness narratives for Israel&apos;s rebellion at Meribah (Num 20:10, 24). Jeremiah consistently returns to the covenantal diagnosis: the catastrophe is not fate or Babylonian power but the logical consequence of Israel&apos;s chosen rebellion.</p>",
    "18": "<p><strong>darkech uma&apos;alalayich asu elleh lach</strong> (<em>darkêk ûmaʿălālayik ʿāśû ʾēlleh lāk</em>): &apos;Your conduct and your actions have brought this on you.&apos; The two-word pair <em>derekh</em> (way/conduct, habitual path of life) and <em>ma&apos;alalim</em> (acts/deeds, individual actions) covers both character and behavior. This is the prophetic announcements of &apos;consequential connection&apos;: the judgment is not arbitrary but organically connected to the sin. <em>Ki mar ki naga ad-libbech</em> (how bitter it has pierced to your very heart) — the same word <em>mar</em> (bitter) used of Miriam (Exod 15:23) and Ruth (Ruth 1:20). The bitterness of the punishment mirrors the bitterness of the rebellion.</p>",
    "19": "<p><strong>meai meai aholelah qirot libbi</strong> (<em>mēʿay mēʿay ʾôḥîlāh qîrôt libbî</em>): &apos;My anguish, my anguish! I writhe in pain! The chambers of my heart are throbbing.&apos; This is one of the most raw expressions of the prophetic <em>pathos</em> in all of Scripture. <em>Meai</em> (intestines/bowels/anguish) is the visceral center of emotion in Hebrew anthropology — the seat of deep feeling (cf. Phil 1:8, &apos;the affections/bowels of Christ Jesus&apos; in the KJV). The doubling (<em>meai meai</em>) is the Hebrew intensifier expressing overwhelmed distress. Whether the speaker is Jeremiah or YHWH through Jeremiah is deliberately ambiguous — the prophet and the divine pathos merge. <em>Hemeh hamah</em> (throbbing/churning) of the heart&apos;s chambers gives a physical image of cardiac palpitation.</p>",
    "20": "<p><strong>shever al-shever niqra ki shuddedah kol-ha&apos;aretz</strong> (<em>šeber ʿal-šeber niqrāʾ kî šuddĕdāh kol-hāʾāreṣ</em>): &apos;Crash after crash — the whole land is laid waste.&apos; The rhetorical device of repetition (<em>sheber al-shever</em>) captures the cascading nature of the disaster: each wave of destruction brings a new one. <em>Sheber</em> (breaking/destruction) is the covenant curse word for catastrophic defeat (Amos 6:6: &apos;the ruin of Joseph&apos;; Isa 30:26: the healing of &apos;the breaking&apos;). The word also appears in the lament context as the &apos;wound&apos; of the people (8:21; 14:17). The sudden destruction of the tent (<em>ohel</em>) and curtains (<em>yeri&apos;ot</em>) in an instant echoes the nomadic vulnerability of life without divine protection.</p>",
    "21": "<p><strong>ad-matai er&apos;eh-nes eshma qol shofar</strong> (<em>ʿad-mātay ʾerʾeh-nes ʾešmaʿ qôl šôpār</em>): &apos;How long must I see the battle standard and hear the blare of the trumpet?&apos; The <em>ad-matai</em> (how long?) is the classic lament formula of the Psalms (Ps 6:3; 13:1-2; 79:5; 80:4). Jeremiah adopts the Psalmic complaint language to express the exhaustion of sustained prophetic intercession: he has been seeing the vision of disaster and proclaiming it, and still the people do not return. The prophet&apos;s endurance is itself becoming a theme of the book (cf. the &apos;Confessions,&apos; chs. 11-20).</p>",
    "22": "<p><strong>ki evili ami oti lo yad&apos;u banim sechel hem velo nevonim hem</strong> (<em>kî ʾĕwîl ʿammî ʾôtî lōʾ yādāʿû bānîm sĕkālîm hēm wĕlōʾ nĕbōnîm hēm</em>): &apos;For my people are foolish — they do not know me; they are stupid children; they have no understanding.&apos; Three synonymous indictments: <em>evil</em> (foolish, morally senseless — the one who &apos;says in his heart there is no God&apos; in Ps 14:1 is a <em>naval</em>, a related word); <em>lo yad&apos;u</em> (they do not know me — covenant knowledge of YHWH is the core deficit); <em>sekalim</em> (stupid, those who act without wisdom). The irony of v. 22b: &apos;they are clever at doing evil, but they do not know how to do good.&apos; The same cognitive capacity that should be used for discerning the good is instead refined for evil.</p>",
    "23": "<p><strong>ra&apos;iti et-ha&apos;aretz vehinei tohu va-vohu</strong> (<em>rāʾîtî ʾet-hāʾāreṣ wĕhinnēh tōhû wābōhû</em>): &apos;I looked at the earth and it was formless and void.&apos; The phrase <em>tohu va-vohu</em> appears only twice in the OT: here and in Gen 1:2, where it describes the uncreated earth before the Spirit moved over it. Jeremiah&apos;s vision is a deliberate reversal of the creation narrative: vv. 23-26 systematically undo the first six days of creation. Light is removed (v. 23 / Day 1), the mountains shake (v. 24 / Day 3), birds flee (v. 25 / Day 5), humans disappear (v. 25 / Day 6), and fertile land returns to desert (v. 26 / Day 3). Covenant judgment is cosmological un-creation: without YHWH&apos;s presence and word, creation reverts to pre-creation chaos. This is one of the most theologically profound images in the prophets.</p>",
    "24": "<p><strong>ra&apos;iti vehinei heharim ra&apos;ashu vegavot hitqosheshu</strong> (<em>rāʾîtî wĕhinnēh hehārîm rāʿāšû wĕkol-haggĕbāʿôt hitqôšāšû</em>): &apos;I looked at the mountains and they were quaking; all the hills were swaying.&apos; The quaking mountains (<em>ra&apos;ash</em>) are a standard theophanic marker — YHWH&apos;s approach causes mountains to tremble (Ps 18:7; Isa 5:25; Nah 1:5). Here the quaking signals not a saving theophany (as at Sinai) but a judgment theophany. The four-fold &apos;I looked and behold&apos; structure (vv. 23-26) mimics the creation narrative&apos;s &apos;and God saw&apos; — but what is seen is dis-creation.</p>",
    "25": "<p><strong>ra&apos;iti vehinei eyn ha&apos;adam</strong> (<em>rāʾîtî wĕhinnēh ʾên hāʾādām</em>): &apos;I looked — there was no human being, and all the birds of the sky had flown away.&apos; <em>Ha&apos;adam</em> (the human / humankind) echoes Gen 1:26-27 where God creates <em>ha&apos;adam</em> in his image on the sixth day. The absence of humans and birds reverses Days 5 and 6 of creation (birds on Day 5, animals and humans on Day 6). The emptied earth — once teeming with life — has returned to the formlessness of Gen 1:2. The birds&apos; departure signals that the ecosystem has collapsed: animals flee a land where YHWH&apos;s presence has withdrawn.</p>",
    "26": "<p><strong>ra&apos;iti vehinei hakarmel hamidbar</strong> (<em>rāʾîtî wĕhinnēh hakkarmel hammidbar</em>): &apos;I looked — the fertile land was a desert; all its cities lay in ruins before the LORD.&apos; <em>Karmel</em> (fertile land, literally &apos;the garden land&apos; or orchard — also the famous mountain range) in contrast with <em>midbar</em> (wilderness/desert) reverses the land&apos;s transformation under covenant blessing. The phrase &apos;before the LORD, because of his fierce anger&apos; (<em>mipnei YHWH mipnei charon appo</em>) names the divine source: the de-creation is not Babylon&apos;s achievement but YHWH&apos;s judgment enacted through Babylon.</p>",
    "27": "<p><strong>kalah lo eseh</strong> (<em>kālāh lōʾ ʾeśeh</em>): &apos;I will not make a complete end.&apos; This brief clause — &apos;a complete end I will not make&apos; — is Jeremiah&apos;s key qualifying restraint on the vision of total destruction (repeated at 5:10, 18; 30:11; 46:28). <em>Kalah</em> (complete end/annihilation) is the strongest term for total destruction. The qualification does not soften the judgment but establishes the covenant basis: Israel is not destroyed like Sodom (though the comparison is implicit) because the Abrahamic promises remain in force. This is the theological nerve of Jeremiah&apos;s entire ministry — YHWH&apos;s judgment is severe but bounded by covenant faithfulness.</p>",
    "28": "<p><strong>dibarti zamoti velo-nichamti velo-ashuv mimmenu</strong> (<em>dibbartî zammōtî wĕlōʾ-niḥamtî wĕlōʾ-ʾāšûb mimmennû</em>): &apos;For I have spoken, I have decided, and I will not relent or turn back from it.&apos; The verb <em>nacham</em> (relent/repent/be comforted) appears in the famous &apos;divine relenting&apos; passages (Exod 32:14; Jonah 3:10; Joel 2:13). Here YHWH declares he will <em>not</em> relent — the judgment is determined. The earth&apos;s mourning (<em>avlah</em>) and the darkening sky anticipate apocalyptic and eschatological imagery; the earth becomes a mourner at YHWH&apos;s decree.</p>",
    "29": "<p><strong>kol-ha&apos;ir nos&apos;ah miqol happarash veroeh qeshet</strong> (<em>kol-hāʿîr nōśāʾāh miqqôl happārāš wĕrōkēb qāšet</em>): &apos;Every city is abandoned; they flee from the noise of horsemen and archers.&apos; The universal abandonment (<em>kol-ha&apos;ir</em>, every city) captures the scale of the flight. The thickets (<em>avim</em>) and rocks (<em>sela&apos;im</em>) where people hide echo Isa 2:10-19&apos;s Day of YHWH scene: &apos;enter the rocks and hide in the ground from before the terror of the LORD.&apos; Hiding in nature is futile refuge — the same theme.</p>",
    "30": "<p><strong>veatt shad&apos;udah ma-ta&apos;asi</strong> (<em>wĕʾatt šādûdāh mah-taʿăśî</em>): &apos;And you, O desolate one — what will you do?&apos; The &apos;you&apos; is personified Jerusalem, addressed as a woman abandoned by her lovers. The three futile actions — dressing in crimson, adorning with gold, painting eyes with kohl — are the preparations of a woman attempting to attract allies (lovers/nations). <em>Puch</em> (kohl, the black eye-paint made from antimony) was common cosmetic preparation. The lovers&apos; rejection (&apos;they want your life&apos;) unmasks the transactional nature of the political alliances Jerusalem was pursuing instead of returning to YHWH.</p>",
    "31": "<p><strong>qol bat-tzion titayapeyach tifros kapeiha</strong> (<em>qôl bat-ṣiyyôn tityappēaḥ tipĕrôś kappêhā</em>): &apos;The cry of Daughter Zion, gasping and reaching out her hands.&apos; The chapter closes with the image of personified Jerusalem as a woman in labor — the same &apos;birth pangs&apos; imagery used in eschatological contexts throughout Scripture (Isa 13:8; 26:17; Mic 4:9-10; John 16:21; 1 Thess 5:3). <em>Bat Tzion</em> (Daughter Zion) is the feminine personification of the city as both a collective and a person in covenant relationship with YHWH. The &apos;reaching out her hands&apos; (<em>paras kapeiha</em>) is the gesture of desperate supplication — the same posture as prayer (Exod 9:29; 1 Kings 8:22; Isa 1:15).</p>"
  },
  "5": {
    "1": "<p><strong>shutu bechutszot Yerushalaim ... im timtze&apos;u ish ... oved mishpat mevaqesh emunat</strong> (<em>šûṭû bĕḥûṣôt yĕrûšālaim ... ʾim timṣĕʾû ʾîš ... ʿōśeh mišpāṭ mĕbaqqēš ʾĕmûnāh</em>): &apos;Go through the streets of Jerusalem ... if you can find even one who acts justly and seeks faithfulness.&apos; The standard echoes Sodom&apos;s renegotiation (Gen 18:23-32): Abraham bargained down to ten righteous people; Jeremiah is told one would suffice for Jerusalem&apos;s forgiveness. <em>Emunat</em> (faithfulness/truth, from <em>aman</em>) is the covenant attribute — the same root as <em>amen</em> — expressing reliability and covenant fidelity. The failure to find even one faithful person is not about sinless perfection but about covenantal orientation: there is no one whose life is fundamentally directed toward YHWH&apos;s justice.</p>",
    "2": "<p><strong>veim YHWH chai yishave&apos;u lachen lashaqer yishave&apos;u</strong> (<em>wĕʾim Yhwh ḥay yiššābēʿû lākēn lašāqer yiššābēʿû</em>): &apos;Even when they say, &apos;As the LORD lives,&apos; they are swearing falsely.&apos; The oath &apos;as the LORD lives&apos; (<em>chai YHWH</em>) is the highest Jewish oath formula (1 Sam 20:3; Jer 4:2). To invoke YHWH&apos;s name as surety for a lie is both perjury and a violation of the third commandment (Exod 20:7). The word <em>shaqer</em> (falsehood/lie) becomes one of Jeremiah&apos;s signature diagnostic terms — appearing over 30 times in the book for prophets, priests, scribes, and the entire nation.</p>",
    "3": "<p><strong>YHWH eineicha halo le&apos;emunat</strong> (<em>Yhwh ʿênêkā hălōʾ lĕʾĕmûnāh</em>): &apos;LORD, do not your eyes look for faithfulness?&apos; The contrast between YHWH&apos;s eyes (<em>eineicha</em>) seeking faithfulness and the people&apos;s refusal to return structures the verse. Three responses to divine discipline are listed and rejected: they felt nothing, they refused to be corrected, they set their faces harder than stone (<em>kashu paneihem misela</em>). The stone-face metaphor is inverted in Ezek 36:26 and Zech 7:12: Israel&apos;s stone-heart/stone-face problem demands the divine surgery of a new heart.</p>",
    "4": "<p><strong>ach ani amarti ach dalim hem niva&apos;alu</strong> (<em>ʾak ʾănî ʾāmartî ʾak-dallîm hēm nôʾālû</em>): &apos;Then I thought, these are only the poor; they are ignorant.&apos; <em>Dal</em> (poor/low/weak) often implies not just economic poverty but social vulnerability and limited access to education. Jeremiah&apos;s initial self-correction — perhaps the poor don&apos;t know better — shows genuine pastoral concern and intellectual honesty. The &apos;way of the LORD&apos; (<em>derekh YHWH</em>) and &apos;the requirements of their God&apos; (<em>mishpat eloheihem</em>) are what the uneducated might genuinely not know. The assumption is immediately tested and proven false in v. 5.</p>",
    "5": "<p><strong>elchah li el-hagdolim vadaveram</strong> (<em>ʾēlĕkāh-lî ʾel-haggĕdōlîm wăʾădabbĕrāh ʾôtām</em>): &apos;So I went to the leaders and spoke to them.&apos; The social experiment — test the uneducated poor, then the educated elite — proves that the moral failure is universal, not class-specific. <em>Yachdav shaveru ol natqu moseirot</em> (they too had together broken the yoke and torn off the bonds): the metaphor of the <em>ol</em> (yoke) for the covenant comes from Jeremiah&apos;s own acted parable in ch. 27-28. &apos;Torn off the bonds&apos; (<em>natqu moseirot</em>) echoes Ps 2:3 where the nations conspire to &apos;burst their bonds asunder&apos; from YHWH and his anointed.</p>",
    "6": "<p><strong>aryeh miyaar hikkam ze&apos;ev araboth yeshaddeddem</strong> (<em>ʾaryēh miyyaʿar hikkam zĕʾēb ʿărābôt yĕšoddĕdēm</em>): &apos;A lion from the forest will attack them, a wolf from the desert will ravage them, a leopard will lurk near their towns.&apos; The three predator escalation (lion, wolf, leopard) builds in danger and ubiquity: the lion attacks directly, the wolf ravages the open fields, the leopard lurks at the city entrance — leaving no safe space. The leopard reappears in 13:23 (&apos;can a leopard change its spots?&apos;) as an image of unreformable human nature. <em>Ki rabbu pish&apos;eihem atsedu meshuboteihem</em> (their rebellions are many and their turnings-away are great): the plural <em>meshubot</em> (apostasies/turnings-back) has the same root as <em>shuv</em> (return) — their turning-away is the opposite of what Jeremiah calls them to do.</p>",
    "7": "<p><strong>eich asalach lach banayich azavuni vayishavu belo-elohim</strong> (<em>ʾêk ʾeslāḥ-lāk bānayik ʿăzābûnî wayyiššāḇĕʿû bĕlōʾ-ʾĕlōhîm</em>): &apos;How can I forgive you for this? Your children have abandoned me and sworn by gods that are no gods.&apos; The <em>eich esalach</em> (how can I forgive?) is a rhetorical question that takes divine forgiveness seriously — not as automatic but as requiring genuine grounds. The &apos;gods that are no gods&apos; (<em>belo-elohim</em>) is a grammatical negation of divinity: they are called gods but have no divine reality. The adultery and flocking to brothels (<em>bate-zonah</em>) is the standard prophetic metaphor for idolatry (Hos 1-3; Ezek 16; Rev 17).</p>",
    "8": "<p><strong>susim mezunim mashcilim hayyu ish el-eshet re&apos;ehu</strong> (<em>sûsîm mĕzunnānîm maśkîlîm hāyû ʾîš ʾel-ʾēšet rēʿēhû</em>): &apos;They are like well-fed, lusty stallions — each neighing after another man&apos;s wife.&apos; The horse metaphor for uncontrolled sexual desire — not merely appetite but the inability to restrain oneself — appears again at 8:6. The Ezekiel parallel (Ezek 23:20) uses the same animal imagery for Judah&apos;s political-spiritual unfaithfulness. The verse is not primarily about individual sexual ethics but about covenant unfaithfulness: the &apos;wife&apos; imagery throughout the prophets frames Israel&apos;s relationship to YHWH as a marriage covenant whose violation is described in terms of adultery.</p>",
    "9": "<p><strong>ha-lo al-eileh efqod neum YHWH veim begoy asher-kazeh lo titnaqem nafshi</strong>: &apos;Should I not call them to account for these things? ... Should I not take vengeance on a nation like this?&apos; The rhetorical refrain at vv. 9 and 29 brackets the entire middle section of ch. 5 with the same divine question. <em>Paqad</em> (call to account/visit/punish) is one of Jeremiah&apos;s key theological verbs for divine intervention in history — YHWH &apos;visits&apos; both in judgment and blessing (29:10: &apos;when I visit you ... I will fulfill my good word&apos;). The verse assumes the answer &apos;yes&apos; — accountability is a necessary feature of the moral universe.</p>",
    "10": "<p><strong>alu besha&apos;aroteiha ushachetu akhala ach kalah al ta&apos;asu</strong> (<em>ʿălû bĕšārôtêhā wĕšaḥātû wĕkālāh ʾal-taʿăśû</em>): &apos;Advance through her vineyards and ravage them, but do not destroy them completely.&apos; The vineyard imagery for Israel (Isa 5:1-7; Ps 80:8-16) makes the partial destruction a pruning rather than an eradication — consistent with the <em>kalah lo eseh</em> principle of 4:27. The branches are stripped because &apos;they do not belong to the LORD&apos; — the branches that bear no covenant fruit are removed, but the vine itself (the covenant community) is not obliterated.</p>",
    "11": "<p><strong>ki bagod bagdu vi beit Yisrael uveit Yehudah</strong> (<em>kî bāgôd bāgĕdû-bî bêt-yiśrāʾēl ûbêt-yĕhûdāh</em>): &apos;For the house of Israel and the house of Judah have acted completely faithlessly.&apos; The doubled <em>bagod bagdu</em> (act faithlessly / act faithlessly) is the infinitive absolute construction for intensity: &apos;they have utterly and completely betrayed.&apos; The naming of both houses — north (Israel) and south (Judah) — makes the indictment comprehensive: this is not a problem of one part of the covenant people but of the entire people. The word <em>bagad</em> (betray/act treacherously) is used of marital betrayal in Mal 2:14-16, reinforcing the marriage-covenant framework.</p>",
    "12": "<p><strong>kieheshu v-YHWH vayomru lo hu</strong> (<em>kiḥăšû bYhwh wayyōmĕrû lōʾ-hûʾ</em>): &apos;They have lied about the LORD and said, &apos;He will do nothing.&apos;&apos; <em>Kachash</em> (lie/be deceptive/deny) is the verb for false denial — the people are not merely ignorant but actively denying that YHWH acts in history. &apos;He will do nothing&apos; (<em>lo hu</em>, literally &apos;not he&apos; — meaning YHWH is inoperative or absent from history) is the functional atheism that Jeremiah diagnoses: acknowledging YHWH&apos;s existence while denying his active governance. The consequences they deny — sword and famine — are the two classic covenant curses of Lev 26 and Deut 28.</p>",
    "13": "<p><strong>vehanevi&apos;im yihyu leruach vehaddavar ein bahem</strong> (<em>wĕhannĕbiʾîm yihyû lĕrûaḥ wĕhaddābār ʾên bāhem</em>): &apos;The prophets are nothing but wind; the word of God is not in them.&apos; <em>Ruach</em> (wind/spirit/breath) is the same word for the divine Spirit. The accusation is a parody: the prophets claim to speak by the <em>ruach</em> (spirit) but are themselves merely <em>ruach</em> (empty wind). The criterion for a true prophet is the presence of the actual <em>davar YHWH</em> (word of God) — content that proves true over time (Deut 18:21-22). The punishment announced for the false prophets — &apos;what they threatened will now happen to them&apos; — is the ironic reversal: they spoke of peace, so peace will be denied them; they denied sword and famine, so they will suffer both.</p>",
    "14": "<p><strong>divaray asem befiv eish veha&apos;am hazeh etzim va&apos;akalam</strong> (<em>dibārāy ʾāśem bĕpîkā ʾēš wĕhāʿam hazzeh ʿēṣîm wăʾăkālatām</em>): &apos;I will make my words in your mouth a fire and these people the wood it will consume.&apos; The fire-of-the-word image (cf. 20:9: &apos;his word is in my heart like a fire&apos;; 23:29: &apos;is not my word like fire?&apos;) makes the prophetic word not merely informational but causally effective: the word of judgment actually brings about what it announces. <em>YHWH Tzvaot</em> (LORD of Armies/Hosts) is Jeremiah&apos;s favored divine title when declaring military judgment — the God of the heavenly armies marshals earthly armies as his instruments.</p>",
    "15": "<p><strong>hineni mevi aleichem goi mimerachok beit Yisrael</strong> (<em>hinnĕnî mēbîʾ ʿălêkem gôy mimmêrāḥōq bêt yiśrāʾēl</em>): &apos;I am bringing a nation against you from far away, O house of Israel.&apos; The description of Babylon at this stage (before 605 BCE) avoids naming the enemy — an &apos;enduring nation, an ancient nation&apos; — which heightens the terror and matches the Deuteronomic curse of Deut 28:49 (&apos;a nation from far away ... whose language you do not know&apos;). The attributes: <em>eitan</em> (powerful/enduring, the same word for a perennial stream), <em>meolam hu</em> (ancient, literally &apos;from of old&apos;), <em>lo-teda leshono</em> (language unknown to you). Unknown language = total otherness.</p>",
    "16": "<p><strong>ashpato kequver patuch</strong> (<em>ʾašpātô kĕqeber pātûaḥ</em>): &apos;Their quivers are like open graves; they are all mighty men.&apos; The open grave (<em>qever patuch</em>) for a quiver is a striking image of lethality: the quiver pours out arrows as a grave consumes bodies, both insatiable. Ps 5:9 applies the same &apos;open grave&apos; image to the throat of the wicked (Rom 3:13 quotes it in the Pauline indictment of universal sin). The arrows from an open-grave quiver make the enemy&apos;s weapons instruments of death indistinguishable from death itself.</p>",
    "17": "<p><strong>ve&apos;achal qetzircha velahmecha ya&apos;akhelu</strong> (<em>wĕʾākal qĕṣîrkā wĕlaḥmekā yōʾkĕlû</em>): &apos;They will devour your harvests and your food — what your sons and daughters depend on for life.&apos; The threefold consumption — harvest, flocks and herds, vines and fig trees — dismantles the entire economic structure of covenantal blessing. In Deut 8:7-10 YHWH promised land with grain, vines, fig trees, olive oil, honey, and rich mineral resources. The nation from afar systematically reverses each of these blessings. The fortified cities they &apos;trust in&apos; (<em>batach</em>) are a faith-object competing with YHWH — and they fail.</p>",
    "18": "<p><strong>vegam bayamim hahem neum YHWH lo-eseh ittechem kalah</strong> (<em>wĕgam bYyāmîm hāhēm nĕʾum Yhwh lōʾ-ʾeśeh ʾittkem kālāh</em>): &apos;Yet even in those days, declares the LORD, I will not make a complete end of you.&apos; The covenant restraint clause repeated from 4:27. Here it appears mid-oracle of invasion, not at the end — which makes it structurally important: YHWH states the limit of judgment even as he announces the judgment&apos;s severity. The survival of Israel through all the covenant curses is itself a theological testimony to the persistence of divine faithfulness.</p>",
    "19": "<p><strong>ka&apos;asher azavtem oti va-ta&apos;avdu elohei nechar be&apos;artzchem</strong> (<em>kaʾăšer ʿăzabtûnî wattaʿabĕdû ʾĕlōhê-nēkār bĕʾarṣkem</em>): &apos;As you abandoned me and served foreign gods in your own land, so now you will serve foreigners in a land that is not your own.&apos; This is the covenant logic of measure-for-measure (<em>middah keneged middah</em>): the punishment mirrors the sin in form. Serving foreign gods voluntarily at home leads to serving foreigners involuntarily in a foreign land. The &apos;service&apos; (<em>avad</em>) vocabulary is identical — the same word for worshipping gods and for slave-labor, connecting idolatry and exile as two forms of the same enslavement.</p>",
    "20": "<p><strong>hagidu zot beveit Ya&apos;akov vehashmi&apos;uha biYehudah</strong> (<em>haggîdû zōʾt bĕbêt yaʿăqōb wĕhaśmîʿûhā bîhûdāh</em>): &apos;Announce this to the house of Jacob; proclaim it in Judah.&apos; The messenger formula linking Jacob (the patriarchal name emphasizing the treacherous-deceiver identity, cf. 9:4) and Judah (the tribal name) frames the oracle as addressed to the whole covenant community in its historical continuity from the patriarch. Jacob&apos;s name (&apos;he supplants/deceives&apos;) is not incidental — Jeremiah&apos;s diagnosis of the people&apos;s deceptive character will be explicit at 9:4.</p>",
    "21": "<p><strong>shim&apos;u na zot am saval velo lev</strong> (<em>šimĕʿû-nāʾ zōʾt ʿam sāḵāl wĕʾên lēb</em>): &apos;Listen to this, you foolish and senseless people — you have eyes but do not see; you have ears but do not hear.&apos; The paradox of sighted blindness and hearing deafness is a fundamental prophetic indictment (Isa 6:9-10; Ezek 12:2). Jesus applies Isa 6:9-10 to explain why he speaks in parables (Matt 13:13-15; Mark 4:12; John 12:40). The people are not physically impaired; they have made a choice not to perceive. <em>Am saval</em> (foolish people) — <em>savel</em> is related to <em>sivroh</em> (refuse/burden); a people who refuse to carry the knowledge that would save them.</p>",
    "22": "<p><strong>halo oti tira&apos;u neum YHWH im mipanai lo tachilu</strong> (<em>hălōʾ-ʾôtî tîrāʾû nĕʾum Yhwh ʾim mippānay lōʾ tāḥîlû</em>): &apos;Should you not fear me? ... I am the one who set the sand as the boundary of the sea.&apos; The argument from creation: the God who maintains the sand-boundary of the sea against its constant pressure is the same God whose law Israel is transgressing. <em>Gvulat olam</em> (eternal boundary/limit that it cannot cross) — <em>olam</em> here means &apos;perpetual,&apos; established as an inviolable order. The sea&apos;s restless surging (<em>galu yitgaashu</em>) but inability to cross the divine boundary is the physical analogy for what Israel should be doing: they should be bounded by YHWH&apos;s law as the sea is bounded by sand. The Creator who controls the sea can certainly control them.</p>",
    "23": "<p><strong>ulaam hayah la&apos;am hazeh lev sorer umorah</strong> (<em>ûlĕhāʿām hazzeh hāyāh lēb sôrēr ûmôreh</em>): &apos;But this people has a stubborn, rebellious heart.&apos; Two adjectives: <em>sorer</em> (stubborn, stiff — the root of <em>sorrer u-moreh</em>, &apos;stubborn and rebellious son&apos; in Deut 21:18, the capital offense) and <em>moreh</em> (rebellious, defying authority). The contrast with v. 22&apos;s sea — the sea obeys YHWH&apos;s boundary but Israel does not — makes Israel less submissive to the Creator than inanimate creation. The heart (<em>lev</em>) that is the problem here will be the target of the new covenant surgery (31:33; Ezek 36:26): a new heart to replace the stubborn one.</p>",
    "24": "<p><strong>velo amru belevavam nirah na et-YHWH elohenu</strong> (<em>wĕlōʾ ʾāmĕrû bĕlibbām nîrāʾ-nāʾ ʾet-Yhwh ʾĕlōhênû</em>): &apos;They do not even say in their hearts, &apos;Let us now fear the LORD our God.&apos;&apos; The seasonal rains — <em>yoreh</em> (early/autumn rains) and <em>malqosh</em> (latter/spring rains) — are the agricultural gifts that signal YHWH&apos;s continued covenant provision (Deut 11:14). The weeks of harvest (<em>shavuot qatzir</em>, appointed harvest weeks) are YHWH&apos;s gift, but the people do not acknowledge the giver. The failure of thanksgiving (<em>yadah</em>) leads directly to the failure of fear (<em>yira</em>): gratitude and reverence for the Creator are the two postures that covenantal life requires and that Israel has abandoned.</p>",
    "25": "<p><strong>avonoteichem hitu eileh tochavot hatebah manecu otchem</strong> (<em>ʿăwōnōtêkem hiṭṭû-ʾēlleh ûḥaṭṭōʾtêkem māneʿû haṭṭôb mikkhem</em>): &apos;Your iniquities have diverted these good things, and your sins have kept them from you.&apos; The hydraulic metaphor: sin acts as a barrier diverting the flow of covenant blessing. <em>Hitu</em> (diverted/turned aside) is used for water channels being turned; the imagery suggests that blessing was on its way but was deflected by the accumulation of sin. This is not arbitrary divine punishment but structural: the covenant&apos;s built-in consequence of disconnection from the source of life.</p>",
    "26": "<p><strong>ki nimtze&apos;u veammi reshi&apos;im</strong> (<em>kî nimṣĕʾû bĕʿammî rĕšāʿîm</em>): &apos;For among my people there are wicked men — they lurk like hunters who set traps.&apos; The predator metaphor shifts from wild animals (v. 6) to human hunters. The trap imagery (<em>mashchit</em>, <em>moqesh</em>) from Ps 91:3 and Amos 3:5 (where the trap is YHWH&apos;s) is here reversed: covenant people are trapping each other. The &apos;cage full of birds&apos; in v. 27 extends the image: what hunters catch, they cage; what the wealthy gain through deception fills their houses like caged birds.</p>",
    "27": "<p><strong>keclub male-of ken bateihem meluim mirma</strong> (<em>kiklûb māleʾ ʿôp kēn bāttêhem mĕlēʾîm mirĕmāh</em>): &apos;As a cage is full of birds, so their houses are full of goods gotten by deceit.&apos; <em>Kelub</em> (cage/basket) is rare — only here and Amos 8:1-2 (&apos;a basket of summer fruit&apos;). The comparison: the ease with which birds are trapped and caged illustrates the ease with which the wealthy trap the vulnerable and fill their houses with unjust gain. <em>Mirmah</em> (deceit/treachery) is the Jeremianic diagnosis of structural economic injustice as fundamentally a form of relational betrayal.</p>",
    "28": "<p><strong>shamnu vayishman gam avaru divrei ra</strong> (<em>šāmĕnû wayyišmānû gam ʿābĕrû dibrê-rāʿ</em>): &apos;They have grown fat and sleek; they surpass all limits in their evil deeds.&apos; <em>Shamen</em> (become fat/rich) is a marker of covenant unfaithfulness in Deut 32:15: &apos;Jeshurun grew fat and kicked.&apos; Wealth fattens and deadens the moral sensibility — the same critique as the &apos;fat heart&apos; of Isa 6:10. The catalog of neglected justice: the orphan (<em>yatom</em>) whose case they do not prosecute and the needy (<em>evyon</em>) whose rights they do not champion are the two emblematic categories of the vulnerable (Exod 22:22; Isa 1:17; Jas 1:27).</p>",
    "29": "<p>The refrain of v. 9 repeated verbatim: &apos;Should I not call them to account for these things? ... Should I not take vengeance on a nation like this?&apos; The structural repetition creates a courtroom rhythm: the indictment (vv. 10-28) is framed by the same divine question at its opening and close. Both times YHWH supplies his own answer implicitly: the accountability is necessary and just.</p>",
    "30": "<p><strong>shama veshaavah niyetah va-aretz</strong> (<em>šammāh wĕšaʿărûrāh niyĕtāh bāʾāreṣ</em>): &apos;A horrible and shocking thing has occurred in the land.&apos; <em>Shama</em> (desolation/horror, causing others to be appalled) and <em>shaavah</em> (shocking/appalling, producing shuddering) are paired exclamations of horror. The same word-pair appears in 18:16; 19:8; 29:18 for the reaction of bystanders to judgment. The buildup to v. 31 makes the identity of the &apos;horrible thing&apos; suspenseful — the answer is not violence from without but corruption from within.</p>",
    "31": "<p><strong>hanevi&apos;im nibbe&apos;u baseqer vehakkohanim yirdu al-yadeihem</strong> (<em>hannĕḇîʾîm nibbĕʾû baššeqer wĕhakkōhănîm yirdû ʿal-yĕdêhem</em>): &apos;The prophets prophesy what is false, the priests exercise authority on their own terms.&apos; The phrase <em>yirdu al-yadeihem</em> (literally &apos;rule by their own hands&apos; or &apos;rule at their own direction&apos;) is difficult — it may mean the priests take fees or exercise power through their own devices rather than YHWH&apos;s authority. The climax is devastating: &apos;my people love it this way.&apos; The false religion is not imposed against the people&apos;s will but is exactly what they want — comfort without accountability. The rhetorical question &apos;but what will you do when the end comes?&apos; (<em>uma-ta&apos;asu beacharitah</em>) closes with the only answer that matters: when the reckoning comes, there is nothing to do.</p>"
  },
  "6": {
    "1": "<p><strong>uzu benei Binyamin miqerev Yerushalaim</strong> (<em>ʿuzzû bĕnê-binyāmîn miqqereb yĕrûšālaim</em>): &apos;Flee to safety, people of Benjamin — get out of Jerusalem!&apos; Jeremiah himself was from Benjamin (1:1 — Anathoth is in Benjamin). The address to Benjamin adds personal weight: these are Jeremiah&apos;s own tribe. Tekoa was the home of Amos (Amos 1:1); its mention may evoke prophetic urgency. Beth-haccerem (perhaps modern Ramat Rachel) is near Jerusalem — the smoke signal (<em>mas&apos;et esh</em>) over it announces the enemy&apos;s location. <em>Ra&apos;ah nishqefah mitzafon</em> (disaster threatens from the north) repeats the refrain of 4:6 and 1:14-15.</p>",
    "2": "<p><strong>hanavah vehaduqah dimmiti bat-tzion</strong> (<em>hannāwāh wĕhaddaqqāh dimmîtî bat-ṣiyyôn</em>): &apos;I will destroy the fair and delicate Daughter Zion.&apos; <em>Navah</em> (pleasant, beautiful — used of Jerusalem&apos;s beauty in Ps 48:2; Lam 1:6) and <em>duqah</em> (delicate/pampered — suggesting luxury and ease) describe Jerusalem at the height of her perceived security. The image of the beautiful pampered woman who will be destroyed inverts the &apos;Daughter Zion&apos; motif used both for comfort (Isa 52:2) and for lament (Lam 1:6; 2:1-4). Shepherds and their flocks camping around her (v. 3) is the siege imagery: the besieging army encampments with their &apos;tents&apos; and &apos;pasturing&apos; divisions.</p>",
    "3": "<p><strong>ro&apos;im uviqram yavo&apos;u eilah taqe&apos;u aleha ohalim</strong> (<em>rōʿîm ûḇiqrām yābōʾû ʾēlêhā tāqĕʿû ʿālêhā ʾōhālîm</em>): &apos;Shepherds with their flocks will come to her and pitch their tents around her.&apos; The enemy commanders are metaphorically &apos;shepherds&apos; controlling their flocks (troops). The &apos;pasturing each his portion&apos; (<em>ra&apos;u ish yado</em>) describes the division of the city among the besieging contingents for systematic plunder. The ironic use of pastoral language for military siege — peaceful shepherd images for violent conquest — intensifies the horror.</p>",
    "4": "<p><strong>qaddeshu aleiha milhamah qumu vena&apos;aleh batzohorayim</strong> (<em>qaddĕšû ʿālêhā milḥāmāh qûmû wĕnaʿăleh baṣṣŏhŏrayim</em>): &apos;Prepare for holy war against her; arise, let us attack at noon.&apos; <em>Qaddeshu milhamah</em> (prepare/consecrate holy war) uses the same vocabulary as Israel&apos;s own holy-war tradition (Josh 3:5; Joel 4:9). The enemy consecrates their war against Jerusalem using Israel&apos;s own ritual vocabulary — a dark irony. The lament &apos;Alas, the day is fading&apos; (<em>oy lanu ki fanah hayom</em>) comes from the enemy&apos;s mouth: they began their assault at noon but have not yet taken the city; night is coming. They resolve to continue through the night (v. 5).</p>",
    "5": "<p><strong>qumu vena&apos;aleh ballaylah vena&apos;ashet armenoteiha</strong> (<em>qûmû wĕnaʿăleh ballaylāh wĕnaśḥîtāh ʾarmĕnôtêhā</em>): &apos;Let us rise up and attack by night and demolish her fortified towers.&apos; <em>Armonot</em> (fortified towers/palaces) are the elite residential structures and citadel towers — the symbols of Jerusalem&apos;s power and pride. Their demolition is the visible sign of conquest. Night attacks in ancient warfare were uncommon and desperate — the enemy&apos;s willingness to fight through the night signals their determination.</p>",
    "6": "<p><strong>ki-koh amar YHWH Tzvaot kirtzu etzah vishfecho al-Yerushalaim solelah</strong> (<em>kî-kōh ʾāmar Yhwh ṣĕbāʾôt kirṭĕzû ʿēṣāh wĕšipĕkû ʿal-yĕrûšālaim sōlĕlāh</em>): &apos;Cut down trees and build a siege ramp against Jerusalem.&apos; The siege ramp (<em>solelah</em>) is an earthwork built up against the city wall to enable assault. The same technique Babylon used historically against Jerusalem and Tyre (Ezek 26:8). The diagnosis: &apos;within her is nothing but oppression&apos; (<em>hi ha&apos;ir haquqad kullah ashaq beqirbah</em>) — the <em>oshaq</em> (oppression/exploitation) within is the cause that brings the siege without.</p>",
    "7": "<p><strong>kehakin bor meimav ken hiqruh rah</strong> (<em>kĕhaqîr bôr mêmêhā kēn hiqĕrāh rāʿāh</em>): &apos;As a well keeps pouring out water, so she keeps pouring out wickedness.&apos; The artesian-well image for persistent sin: the well produces water without stopping or requiring effort; Jerusalem produces wickedness with the same effortless constancy. <em>Chamas ve-shod</em> (violence and devastation) — the same word-pair used of the reason for Noah&apos;s flood (Gen 6:11, 13: <em>chamas</em>). Before YHWH continually (<em>negdi tamid</em>): the sin is performed as if YHWH is not watching, but it is constantly before his eyes.</p>",
    "8": "<p><strong>hivvaseeri Yerushalaim pen-tiqah nafshi mimmech</strong> (<em>hiwwāsĕrî yĕrûšālaim pen-tiqaʿ nafšî mimmēk</em>): &apos;Take warning, O Jerusalem, or I will turn away from you.&apos; <em>Hiwwaseri</em> (be warned/corrected — take the discipline) is the verb from <em>musar</em> (correction/discipline) — the same root as the wisdom tradition&apos;s instruction. The threat is not destruction but abandonment: <em>pen-tiqah nafshi mimmech</em> (lest I turn away from you). The departure of YHWH&apos;s presence (<em>nephesh</em>, divine soul/self) is worse than judgment; it is the theological catastrophe that Ezekiel will actually portray happening in chs. 8-11.</p>",
    "9": "<p><strong>kaleh yiglellu sha&apos;erit Yisrael ke-gannan al-hagafen</strong> (<em>kālēh yeʾolĕlû šĕʾērît yiśrāʾēl kĕbōṣēr ʿal-haggāpen</em>): &apos;Carefully glean the remnant of Israel as a vinedresser gleans a vine.&apos; The gleaning (<em>olel</em>) metaphor: after the main harvest, harvesters passed through the vineyard again picking the overlooked clusters. By Deuteronomic law (Deut 24:21; Lev 19:10) the gleanings were left for the poor. Here YHWH commands a thorough gleaning — even the &apos;remnant of Israel&apos; (<em>she&apos;erit Yisrael</em>) will be gathered up in the judgment, leaving nothing behind on the vine. The remnant language is double-edged: elsewhere (Jer 23:3; Isa 10:20-21) the remnant is the saved group, but here it is the group targeted for thorough judgment.</p>",
    "10": "<p><strong>al-mi adabera ve&apos;a&apos;idah veyishme&apos;u hine arlatah oznam</strong> (<em>ʾel-mî ʾădabbĕrāh wĕʾāʿîdāh wĕyišmāʿû hinnēh ʿorlātāh ʾoznām</em>): &apos;To whom shall I speak and give warning so that they will listen? Look, their ears are uncircumcised.&apos; <em>Arlatah oznam</em> (uncircumcised ears) is the auditory parallel to 4:4&apos;s uncircumcised heart. The physical sign of the Abrahamic covenant (circumcision) becomes an image for spiritual receptivity in multiple registers: ear (6:10), heart (4:4; Deut 10:16), and lips (Exod 6:12, 30 — &apos;uncircumcised lips&apos; = poor speaker). The word of YHWH has become &apos;an object of scorn&apos; (<em>cherepah</em>) to them — they take no pleasure in it.</p>",
    "11": "<p><strong>veth chemath YHWH male&apos;ti nile&apos;iti hakil</strong> (<em>wĕʾēt ḥămat Yhwh māleʾtî nilʾêtî hākêl</em>): &apos;So I am full of the LORD&apos;s fury; I am worn out with holding it in.&apos; The image of Jeremiah as a vessel filled with divine wrath too full to be contained reverses Isa 6:8 where the prophet volunteers; here Jeremiah is compelled by the weight of what he carries. <em>Nile&apos;iti hakil</em> (worn out with holding it in / exhausted from restraint) — the prophet cannot remain silent because the divine message has overpowered his resistance (cf. 20:9: &apos;if I say I will not mention him ... his word is in my heart like a burning fire shut up in my bones&apos;).</p>",
    "12": "<p><strong>venasabbu bateihem le&apos;acherim sadot unnashim yachdav</strong> (<em>wĕnāsabbû bāttêhem lĕʾăḥērîm śādôt ûnāšîm yaḥdāw</em>): &apos;Their houses will be given to others, along with their fields and wives.&apos; The transfer of houses, fields, and wives is the covenant curse explicitly listed in Deut 28:30: &apos;you will build a house but not live in it ... you will plant a vineyard but not use it ... your wife will be given to another.&apos; Jeremiah is announcing the historical actualization of the Deuteronomic covenant curses.</p>",
    "13": "<p><strong>ki miqatanam ad-gedolam kulloh botze&apos; vatza vemin-navi ve&apos;ad-kohen kulloh oseh sheqer</strong> (<em>kî miqqĕṭannām wĕʿad-gĕdôlām kullô bōṣēaʿ bāṣaʿ ûminnābîʾ wĕʿad-kōhēn kullô ʿōśeh šāqer</em>): &apos;For from the least to the greatest of them, everyone is greedy for dishonest gain; from prophet to priest, everyone acts deceitfully.&apos; <em>Botze&apos; vatza</em> (cutting off a cut / greedy for gain) — the doubled form intensifies the avarice: covetous through and through. The phrase &apos;from the least to the greatest&apos; (<em>min-qatanam ad-gedolam</em>) makes the corruption universal across social strata, and &apos;from prophet to priest&apos; makes it universal across religious authorities. This verse is quoted in 8:10b (nearly verbatim) — it frames both chs. 6 and 8 with the same diagnosis.</p>",
    "14": "<p><strong>vayirpe&apos;u et-shever bat-ami al-neqalah lemor shalom shalom veyn shalom</strong> (<em>wayrappĕʾû ʾet-šeber bat-ʿammî ʿal-nĕqallāh lēmōr šālôm šālôm wĕʾên šālôm</em>): &apos;They treat the wound of my people as though it were minor, saying, &apos;Peace, peace,&apos; when there is no peace.&apos; The doubled <em>shalom shalom</em> is the grammatical intensifier — &apos;complete peace, total peace&apos; — that makes the false assurance more emphatic, not less. The verb <em>repha</em> (heal/treat) applied to <em>shever</em> (breaking/fracture) means treating a serious break superficially: the false prophets apply a bandage to a fracture that requires surgery. This verse is the most quoted Jeremiah phrase in NT secondary literature on false prophecy (cf. Ezek 13:10: &apos;they have misled my people, saying Peace, when there is no peace&apos;). Paul&apos;s &apos;peace and safety&apos; formula in 1 Thess 5:3 draws on this exact prophetic tradition.</p>",
    "15": "<p><strong>hahivoshu ki to&apos;evah asu gam bosh lo yevoshu gam hachliim lo yad&apos;u</strong> (<em>hăhôbîšû kî tôʿēbāh ʿāśû gam-bōš lōʾ-yēbōšû gam-haklîm lōʾ yādāʿû</em>): &apos;Are they ashamed of their detestable conduct? No, they have no shame at all; they do not even know how to blush.&apos; The conscience has been anesthetized: <em>bosh</em> (be ashamed) and <em>hachlim</em> (blush) are the two natural responses of moral awareness to violation. Their absence marks the progressive hardening that Jeremiah diagnoses (3:3: &apos;you have the forehead of a prostitute; you refuse to be ashamed&apos;). The parallelism with Zeph 3:5 (&apos;the unjust knows no shame&apos;) and with Paul&apos;s &apos;their conscience is seared&apos; (1 Tim 4:2) identifies a recurring diagnostic of moral deterioration.</p>",
    "16": "<p><strong>koh amar YHWH imdu al-drakhim ure&apos;u ushalu lenatevot olam ei-ze derekh hatov velkhu vah umtze&apos;u margoa lenapshekhem</strong> (<em>kōh ʾāmar Yhwh ʿimĕdû ʿal-dĕrākîm ûrĕʾû wĕšaʾălû lĕnĕtîbôt ʿôlām ʾê-zeh derek haṭṭôb wĕlĕkû-bāh ûmĕṣĕʾû margeʿā lĕnapšĕkem</em>): &apos;Stand at the crossroads and look; ask for the ancient paths, ask where the good way is, and walk in it. You will find rest for your souls.&apos; <em>Netivot olam</em> (paths of the age / ancient paths) are the time-tested, traditional ways of covenant faithfulness — not arbitrary conservatism but the accumulated wisdom of what has proven to lead to life. The phrase <em>margoa lenaphshechem</em> (rest for your souls) is quoted almost verbatim by Jesus in Matt 11:29: &apos;you will find rest for your souls.&apos; Jesus does not cite a path but presents himself as the path — &apos;I am the way&apos; (John 14:6) — replacing the question &apos;where is the good way?&apos; with the answer &apos;I am the way.&apos; Israel&apos;s response here — &apos;we will not walk in it&apos; — is exactly the response Jesus anticipates from his own generation.</p>",
    "17": "<p><strong>vehaqimoti aleichem tzofim</strong> (<em>wăhaqqimōtî ʿălêkem ṣōfîm</em>): &apos;I appointed watchmen over you and said, &apos;Listen to the sound of the trumpet!&apos;&apos; <em>Tzofim</em> (watchmen) is the prophetic self-designation par excellence (Ezek 3:17; 33:7: &apos;I have made you a watchman for the house of Israel&apos;). The watchman&apos;s role: sound the alarm when danger approaches. The trumpet sound is the same covenant alarm of v. 1 and 4:5. Israel&apos;s response — &apos;we will not listen&apos; — creates the culpability: they were warned through YHWH&apos;s appointed watchmen and explicitly refused. Ezekiel 33:4-5 develops the watchman logic: if the watchman warns and the person refuses to heed, their blood is on their own head.</p>",
    "18": "<p><strong>lachen shime&apos;u hagoyim ude&apos;i ha&apos;edah et-asher bam</strong> (<em>lākēn šimĕʿû haggôyim ûdĕʿî hāʿēdāh ʾēt ʾăšer-bām</em>): &apos;Therefore, you nations, hear; you witnesses, know what has happened among them.&apos; The nations are summoned as a courtroom audience — the covenant lawsuit (<em>rib</em>) of YHWH against Israel goes public before the international community. This is the humiliation Jeremiah warned about in 4:16: the nations hear of Jerusalem&apos;s shame. The nations-as-witnesses motif appears throughout the prophets (Mic 1:2; Isa 34:1) where cosmic observation of covenant judgment establishes YHWH&apos;s justice before all peoples.</p>",
    "19": "<p><strong>shime&apos;i ha&apos;aretz hineni mevi ra&apos;ah el-ha&apos;am hazeh peri machshevotam</strong> (<em>šimĕʿî hāʾāreṣ hinnĕnî mēbîʾ rāʿāh ʾel-hāʿam hazzeh pĕrî maḥšĕbôtām</em>): &apos;Listen, O earth: I am going to bring disaster on this people — the direct result of their own schemes.&apos; <em>Peri machshevotam</em> (the fruit/result of their schemes): the disaster is organically connected to the sin, as fruit to its tree. The word <em>peri</em> (fruit) establishes the agricultural metaphor of consequential connection — what you plant bears its own kind of fruit. The rejection of Torah (<em>torati</em>, my law) and the words (<em>devarai</em>) of YHWH is the specific cause named.</p>",
    "20": "<p><strong>lamah-zeh li levonah misheva tavo uqaneh hatov meeretz merhaq</strong> (<em>lāmmāh-zeh lî lĕbōnāh miššĕbāʾ tābōʾ ûqāneh haṭṭôb mēʾereṣ mêrḥāq</em>): &apos;What good is it if incense is brought to me from Sheba and fragrant cane from a distant land?&apos; Sheba (Arabia/Ethiopia) was famous for spices and incense. The two items — <em>levonah</em> (frankincense, the purest liturgical incense) and <em>qaneh hatov</em> (sweet calamus/fragrant cane) — represent the most expensive and exotic offerings available. Their rejection underlines that YHWH&apos;s complaint is not about the quality of the offerings but their moral context: &apos;your burnt offerings are not acceptable ... your sacrifices do not please me.&apos; The same critique as Isa 1:11-17 and Amos 5:21-24: ritual without justice is abomination.</p>",
    "21": "<p><strong>lachen koh-amar YHWH hinneni noten el-ha&apos;am hazeh mikhsholim</strong> (<em>lākēn kōh-ʾāmar Yhwh hinnĕnî nōtēn ʾel-hāʿam hazzeh mikšōlîm</em>): &apos;Therefore this is what the LORD says: I am going to put obstacles before this people, and they will stumble over them.&apos; <em>Mikhsholim</em> (stumbling blocks/obstacles) is used both literally and figuratively for whatever causes covenant Israel to fall (Ezek 7:19; 14:3-4). That fathers and sons, neighbors and friends &apos;all perish together&apos; (<em>yachadu yovadu</em>) captures the social solidarity of covenant judgment: when a society&apos;s leaders and people together have rejected YHWH, the consequences are shared across all relationships.</p>",
    "22": "<p><strong>hinei am ba meeretz tzafon vegoi gadol yeur miyarketei aretz</strong> (<em>hinnēh ʿam bāʾ mēʾereṣ ṣāpôn wĕgôy gādôl yēʿôr miyyarkĕtê ʾāreṣ</em>): &apos;Look, an army is coming from the northern country, a great nation is being roused from the far ends of the earth.&apos; The northern foe (<em>eretz tzafon</em>) of 1:13-15 and 4:6 is here a &apos;great nation&apos; (<em>goi gadol</em>) stirred from the furthest reaches of the earth. <em>Yeur</em> (roused/stirred up) — as one arouses a sleeping person or stirs up a fire. YHWH is the one rousing the enemy (cf. Isa 45:13: &apos;I will rouse him up in righteousness&apos;); the enemy is YHWH&apos;s instrument, not an autonomous threat.</p>",
    "23": "<p><strong>qeshet vekidon yachaziqo akhzari hu velo yerachemu</strong> (<em>qešet wĕkîdôn yaḥăzîqû ʾakzārî hûʾ wĕlōʾ yĕraḥēmû</em>): &apos;They are armed with bow and spear; they are ruthless and without mercy.&apos; The three-fold characterization — <em>akhzari</em> (ruthless/cruel), <em>lo yerachemu</em> (without mercy), and the sea-roaring sound of their approach — strips away any human quality from the invaders. The comparison to the sea (&apos;they sound like the roaring sea&apos;) echoes the chaos-sea imagery of the psalms and Isaiah where the nations are compared to the raging sea (Ps 65:7; Isa 17:12-13). The address &apos;O Daughter Zion&apos; shifts the personification to the recipient of this unstoppable force.</p>",
    "24": "<p><strong>shama&apos;nu et-shim&apos;o rafu yadeynu tzarah heheziqatnu chil keyoledah</strong> (<em>šāmaʿnû ʾet-šimʿô rāpû yādênû ṣārāh hĕḥezîqātnû ḥîl kĕyôlēdāh</em>): &apos;We have heard the report — our hands go limp; distress has seized us, pain like a woman in labor.&apos; The first-person plural shifts the perspective to the Judean civilian response. &apos;Hands going limp&apos; (<em>rafu yadeynu</em>) is the paralysis of terror, the same idiom as Rahab&apos;s report about Canaan&apos;s response to Israel: &apos;our hearts melted and everyone&apos;s courage failed&apos; (Josh 2:11). The birth-pain metaphor (<em>chil keyoledah</em>) for the pain of invasion creates the eschatological resonance: the same image in 1 Thess 5:3 (&apos;sudden destruction comes upon them like labor pains&apos;) draws on this Jeremianic tradition.</p>",
    "25": "<p><strong>al-tetze&apos;u hasadeh vevadarech al-tele&apos;chu ki cherev le-oyev magor misaviv</strong> (<em>ʾal-tēṣĕʾû haśśādeh wĕbadderek ʾal-tēlēkû kî ḥereb lĕʾôyēb māgôr missābîb</em>): &apos;Do not go out into the fields or walk along the roads, for the enemy is armed with a sword; terror is on every side.&apos; <em>Magor misaviv</em> (terror/fear on every side) becomes Jeremiah&apos;s own signature phrase, thrown at him in mockery by his persecutors (20:3: &apos;Jeremiah said, YHWH has not named you Pashhur but Magor Misaviv&apos;). The phrase becomes both a prophecy and a lived experience for Jeremiah himself — he becomes the one who lives in terror on every side, embodying the oracle he delivers.</p>",
    "26": "<p><strong>bat-ami chigri-saq vehitpallaghshi ba-efer</strong> (<em>bat-ʿammî ḥigĕrî-śaq wĕhitpallĕgĕšî bāʾēper</em>): &apos;O my dear people, put on sackcloth and roll in the ashes; mourn with bitter weeping as for an only child.&apos; <em>Bat ami</em> (daughter of my people) is Jeremiah&apos;s most personal address — not the formal &apos;house of Israel&apos; but his own people, the child of his community. The grief called for is <em>ebel yachid</em> (mourning for an only child) — the most acute form of grief in the ancient world, the grief without replacement or succession. Amos 8:10 uses the same image for eschatological grief: &apos;I will make it like the mourning for an only son.&apos; The suddenness (&apos;the destroyer is about to come upon us suddenly&apos;) prevents the preparation that would allow grief to be managed.</p>",
    "27": "<p><strong>bachen nataticha be&apos;ami mivtzar utiyde&apos;a uvachanta et-darkam</strong> (<em>bāḥôn nĕtattîkā bĕʿammî miḇṣār wĕtiṯĕdaʿ ûbāḥantā ʾet-darkām</em>): &apos;I have made you an assayer and a tester among my people, so that you may know and test their conduct.&apos; <em>Bachar/bachen</em> (assayer/tester) is the metallurgical term for testing the purity of metals — Jeremiah is cast in the role of the assay-master who evaluates the quality of the ore. The calling is parallel to Jeremiah&apos;s initial call (1:5, 10: &apos;I appointed you ... to pluck up and tear down ... and to plant and build&apos;) but here the evaluative function is foregrounded. The results of the assay follow in vv. 28-30.</p>",
    "28": "<p><strong>kullam sarei sorarim holkhei rakhil nechoshet uvarzel kullam mashchitim hem</strong> (<em>kullām śārê-sōrĕrîm hōlĕkê-rākîl nĕḥōšet ûbarzel kullām mašḥîtîm hēm</em>): &apos;They are all rebellious troublemakers, going about spreading slander; they are bronze and iron — utterly corrupt.&apos; The metallurgical assay result: not silver or gold but <em>nechoshet uvarzel</em> (bronze and iron) — base metals that cannot be refined into the precious. The term <em>mashchitim</em> (corrupt/corrupted, the same root as the corruption of Noah&apos;s generation in Gen 6:12) is the adjective for something utterly spoiled. The character description — rebellious (<em>sorerim</em>) and slanderous (<em>holkhei rakhil</em>) — adds the social damage they do.</p>",
    "29": "<p><strong>naphach mapuach bakesh va&apos;esh tamam areph kesef lashave tzareph</strong> (<em>nāpaḥ mappûaḥ bāqeš bāʾēš tāmam ʾārep kesep lešāwĕʾ ṣārēp</em>): &apos;The bellows blow fiercely; the lead is consumed in the flames; the smelter smelts in vain — the wicked are not drawn off.&apos; The full smelting process: bellows (<em>mappuach</em>) force air to increase heat; lead is added as flux to absorb impurities; the smelter (<em>tzaraph</em>) applies heat to draw off the dross. When the process fails — &apos;the wicked are not drawn off&apos; (<em>lo nitaqu resha&apos;im</em>) — the ore is ruined. The image of the failed refinery process was taken up in Isa 1:25 (&apos;I will thoroughly purge away your dross&apos;) and Ezek 22:18-22 where Israel is described as the dross left after the silver has been removed.</p>",
    "30": "<p><strong>kesef nivzah qora&apos;u lahem ki ma&apos;as YHWH bam</strong> (<em>kesep nizʾāb qārĕʾû lāhem kî māʾas Yhwh bām</em>): &apos;They will be called rejected silver, for the LORD has rejected them.&apos; <em>Kesef nivzah</em> (rejected/worthless silver) is the assay verdict: the ore that went through the refinery and came out as waste, not as pure metal. The final word <em>ma&apos;as YHWH bam</em> (the LORD has rejected them) echoes YHWH&apos;s rejection of Saul (1 Sam 15:23, 26) and of the Eli priesthood (1 Sam 2:30). Being &apos;called&apos; rejected silver (<em>qara&apos;u lahem</em>) means the designation is public and permanent — a verdict announced rather than merely felt. The chapter ends on rejection, not judgment — the worse fate is not to be punished but to be assessed as worthless and discarded.</p>"
  }
}

def main():
    existing = load_comm('mkt-original', 'jeremiah')
    merge_comm(existing, JER_ORIGINAL)
    save_comm('mkt-original', 'jeremiah', existing)

    out = json.loads((ROOT / 'data/commentary/mkt-original/jeremiah.json').read_text())
    il  = json.loads((ROOT / 'data/interlinear/jeremiah.json').read_text())

    all_ok = True
    for ch in range(4, 7):
        ck = str(ch)
        missing = set(il.get(ck, {}).keys()) - set(out.get(ck, {}).keys())
        if missing:
            print(f'ch {ch} STILL MISSING: {sorted(missing, key=int)}')
            all_ok = False
        else:
            print(f'ch {ch}: complete ({len(out.get(ck,{}))} verses)')
    if all_ok:
        print('All verses present')

if __name__ == '__main__':
    main()
